#include "sht4x.h"
#include "sensirion_i2c_hal.h"
#include "sensirion_common.h"

static uint8_t _i2c_address;

static float _convert_ticks_to_celsius(uint16_t ticks) {
    return (float)ticks * 175.0f / 65535.0f - 45.0f;
}

static float _convert_ticks_to_rh(uint16_t ticks) {
    return (float)ticks * 125.0f / 65535.0f - 6.0f;
}

int16_t sht4x_measure_high_precision(int32_t* temperature, int32_t* humidity) {
    uint8_t command = 0xFD;
    uint8_t buffer[6];
    int16_t error = sensirion_i2c_hal_write(_i2c_address, &command, 1);
    if (error) {
        return error;
    }
    sensirion_i2c_hal_sleep_us(10000);
    error = sensirion_i2c_hal_read(_i2c_address, buffer, 6);
    if (error) {
        return error;
    }
    uint16_t temperature_ticks = sensirion_common_bytes_to_uint16_t(&buffer[0]);
    uint16_t humidity_ticks = sensirion_common_bytes_to_uint16_t(&buffer[3]);

    *temperature = (17500 * temperature_ticks / 65535) - 4500;
    *humidity = (12500 * humidity_ticks / 65535) - 600;

    return 0;
}

