int16_t sht4x_serial_number(uint32_t* serial_number) {
    uint8_t command = 0x89;
    uint8_t buffer[6];
    int16_t error = sensirion_i2c_hal_write(_i2c_address, &command, 1);
    if (error) {
        return error;
    }
    sensirion_i2c_hal_sleep_us(10000);
    error = sensirion_i2c_hal_read(_i2c_address, buffer, 6);
    if (error) {
        return error;
    }
    *serial_number = sensirion_common_bytes_to_uint32_t(&buffer[0]);
    return 0;
}

int16_t sht4x_soft_reset() {
    uint8_t command = 0x94;
    int16_t error = sensirion_i2c_hal_write(_i2c_address, &command, 1);
    if (error) {
        return error;
    }
    sensirion_i2c_hal_sleep_us(2000);
    return 0;
}

int16_t sht4x_probe() {
    uint32_t serial;
    return sht4x_serial_number(&serial);
}

int16_t sht4x_measure_blocking_read(float* temperature, float* humidity) {
    int32_t temp_milli;
    int32_t hum_milli;
    int16_t error = sht4x_measure_high_precision(&temp_milli, &hum_milli);
    if (error) {
        return error;
    }
    *temperature = (float)temp_milli / 100.0f;
    *humidity = (float)hum_milli / 100.0f;
    return 0;
}

int16_t sht4x_measure_blocking_read_raw(int32_t* temperature, uint32_t* humidity) {
    int32_t temp_milli;
    int32_t hum_milli;
    int16_t error = sht4x_measure_high_precision(&temp_milli, &hum_milli);
    if (error) {
        return error;
    }
    *temperature = temp_milli;
    *humidity = (uint32_t)hum_milli;
    return 0;
}
int16_t sht4x_init(uint8_t i2c_address) {
    _i2c_address = i2c_address;
    return sht4x_soft_reset();
}
